#!/usr/bin/env python3
# MMOnsterpatch Official Server compact bootstrap.
# This file bundles the server modules into one visible runtime file.
import base64, os, sys, tempfile, runpy

BUNDLED_MODULES = {'mmonsterpatch_mmo_core.py': '', 'mmonsterpatch_moderation_core.py': '', 'mmonsterpatch_server.py': '', 'mmonsterpatch_social_core.py': '', 'mmonsterpatch_tradingpost_core.py': '', 'mmonsterpatch_world_config.py': ''}

def _script_dir():
    try:
        return os.path.dirname(os.path.abspath(__file__))
    except Exception:
        return os.getcwd()

def _ensure_default_args(root):
    has_config = any(a == '--config' or a.startswith('--config=') for a in sys.argv[1:])
    if not has_config:
        cfg = os.path.join(root, 'configs', 'worldserver.ini')
        sys.argv.extend(['--config', cfg])

def _main():
    root = _script_dir()
    os.chdir(root)
    for d in ('data', 'logs', 'backups'):
        os.makedirs(os.path.join(root, d), exist_ok=True)
    sys.dont_write_bytecode = True
    temp_root = os.path.join(tempfile.gettempdir(), 'MMOnsterpatchServer_runtime')
    os.makedirs(temp_root, exist_ok=True)
    for filename, payload in BUNDLED_MODULES.items():
        path = os.path.join(temp_root, filename)
        with open(path, 'wb') as f:
            f.write(base64.b64decode(payload))
    if temp_root not in sys.path:
        sys.path.insert(0, temp_root)
    _ensure_default_args(root)
    runpy.run_module('mmonsterpatch_server', run_name='__main__')

if __name__ == '__main__':
    _main()
